import React, { useEffect } from 'react';
import styled from 'styled-components';
import AOS from 'aos';
import 'aos/dist/aos.css';
import Footer from '../components/Footer';

const TeamPage = styled.div`
  min-height: 100vh;
  background: #000;
  padding-top: 80px;
`;

const TeamSection = styled.section`
  padding: 100px 10%;
`;

const Header = styled.div`
  text-align: center;
  margin-bottom: 60px;

  h2 {
    font-size: 3rem;
    color: #00FFFF;
    margin-bottom: 20px;
    position: relative;
    display: inline-block;

    &::after {
      content: '';
      position: absolute;
      bottom: -10px;
      left: 50%;
      transform: translateX(-50%);
      width: 80px;
      height: 4px;
      background: linear-gradient(to right, #00FFFF, #00BFFF);
      border-radius: 2px;
    }
  }
`;

const TeamGrid = styled.div`
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(250px, 1fr));
  gap: 30px;
  margin-top: 50px;
`;

const TeamCard = styled.div`
  background: rgba(255, 255, 255, 0.05);
  border-radius: 15px;
  padding: 20px;
  text-align: center;
  border: 1px solid rgba(255, 255, 255, 0.1);
  transition: transform 0.3s ease;

  &:hover {
    transform: translateY(-10px);
  }

  img {
    width: 200px;
    height: 200px;
    border-radius: 50%;
    margin-bottom: 20px;
    object-fit: cover;
  }

  h3 {
    color: #00FFFF;
    margin: 10px 0;
  }

  p {
    color: rgba(255, 255, 255, 0.8);
    margin-bottom: 20px;
  }

  .social-icons {
    display: flex;
    justify-content: center;
    gap: 15px;

    a {
      color: #00FFFF;
      font-size: 1.2rem;
      transition: transform 0.3s ease;

      &:hover {
        transform: scale(1.2);
      }
    }
  }
`;

const Team = () => {
  useEffect(() => {
    AOS.init({
      duration: 1000,
      once: true,
      mirror: false
    });
  }, []);

  const teamMembers = [
    {
      name: "Mayank Dhusia",
      position: "Core Team",
      image: require("../assets/mayank.jpeg"),
      instagram: "https://www.instagram.com/m01ayank0",
      linkedin: "https://www.linkedin.com/in/mayank-dhusia-807b3335a"
    },
    {
      name: "Piyush Saini",
      position: "Technical Lead",
      image: require("../assets/piyush.jpg"),
      instagram: "http://instagram.com/piyush_saini_40",
      linkedin: "https://www.linkedin.com/in/piyushsaini2004/"
    }
    // Add more team members here
  ];

  return (
    <TeamPage>
      <TeamSection>
        <Header>
          <h2 data-aos="fade-up">Our Team</h2>
        </Header>
        <TeamGrid>
          {teamMembers.map((member, index) => (
            <TeamCard key={index} data-aos="fade-up" data-aos-delay={100 * (index + 1)}>
              <img src={member.image} alt={member.name} />
              <h3>{member.name}</h3>
              <p>{member.position}</p>
              <div className="social-icons">
                <a href={member.instagram} target="_blank" rel="noopener noreferrer">
                  <i className="fab fa-instagram"></i>
                </a>
                <a href={member.linkedin} target="_blank" rel="noopener noreferrer">
                  <i className="fab fa-linkedin-in"></i>
                </a>
              </div>
            </TeamCard>
          ))}
        </TeamGrid>
      </TeamSection>
      <Footer />
    </TeamPage>
  );
};

export default Team;
